/**
 * LoginForm — Generated by Elmoorx AI Copilot
 * Production-ready login form with auto-sanitization and CSRF protection.
 */

import { $state, island, h } from "@elmoorx/runtime";

const LoginForm = island(() => {
  const email = $state("");
  const password = $state("");
  const error = $state(null);
  const loading = $state(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    error.set(null);
    loading.set(true);
    try {
      const creds = { email: email().trim(), password: password() };
      if (!creds.email || !creds.password) {
        error.set("Email and password are required");
        return;
      }
      const res = await fetch("/api/auth/login", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(creds),
      });
      if (!res.ok) {
        const data = await res.json();
        error.set(data.message || "Login failed");
        return;
      }
      window.location.href = "/dashboard";
    } catch (err) {
      error.set("Network error — please try again");
    } finally {
      loading.set(false);
    }
  };

  return h("form", { onSubmit: handleSubmit, class: "login-form" },
    h("h2", { class: "login-title" }, "Sign in to your account"),
    h("div", { class: "field" },
      h("label", { for: "email" }, "Email"),
      h("input", { type: "email", id: "email", value: () => email(),
        onInput: (e) => email.set(e.target.value), required: true })
    ),
    h("div", { class: "field" },
      h("label", { for: "password" }, "Password"),
      h("input", { type: "password", id: "password", value: () => password(),
        onInput: (e) => password.set(e.target.value), required: true })
    ),
    () => error() ? h("div", { class: "error" }, error()) : null,
    h("button", { type: "submit", disabled: () => loading() },
      () => loading() ? "Signing in..." : "Sign in")
  );
});

export default function Page() {
  return h("main", null, LoginForm({}));
}
